  { id: 'tradeable', label: 'Tradeable', defaultVisible: false, required: false, requiredFeature: 'ai_ticker_recommendations' },
];

const LS_COLUMN_KEY = 'instnews_column_visibility';
const LS_COLUMN_ORDER_KEY = 'instnews_column_order';

