  sidebarOpen: false,
  modalOpen: false,
  detailModalOpen: false,
  detailItem: null,
  userTier: null,
  userFeatures: {},
  soundEnabled: false,
  columnVisibility: {},
  columnOrder: COLUMN_DEFS.map(c => c.id),
  columnSettingsOpen: false,
};

// ---------------------------------------------------------------------------
// DOM References
