function init() {
  loadColumnVisibility();
  loadColumnOrder();
  renderTableHeader();
  renderSkeleton();
  renderSources();
  bindEvents();
  updateClock();
  initAuth();

  // Start clock
  setInterval(updateClock, 1000);

  // Initial fetch
  fetchNews();
  fetchStats();
  fetchSources();

  // Start auto-refresh
  startAutoRefresh();

  // Periodic stats refresh (every 30s)
  setInterval(() => {
    fetchStats();
    fetchSources();
  }, 30000);
}

// Start when DOM is ready
if (document.readyState === "loading") {
  document.addEventListener("DOMContentLoaded", init);
} else {
  init();
}

